import { useEffect, useState } from "react";
import { getAccounts, showElements } from "../../global/main.js";
import { toBackground } from "../../messages/index.js";
import "../css/main.css";
import Header from "./header";
import AllApps from "./all-apps";
import portalPageClassifier from "../../global/oneloginApiServer/portalPageClassifier.js";

/**
 * @TODO
 * On load of the extension, the onelogin portal refreshes everytime,
 * need to figure out a way to avoid this. (Maybe a accounts cache would fix it? Thinkkkkkk)
 */

const App = () => {
  const [hide, setHide] = useState({
    error: true,
    warning: true,
    spinner: true,
    loginButton: true,
  });
  const [message, setMessage] = useState({ warning: "Connecting", error: ""});
  const [serverUrl, setServerUrl] = useState("");
  const [accounts, setAccounts] = useState([]);
  const [filterValue, setFilterValue] = useState("");
  const [fetchedAccounts, setFetchedAccounts] = useState(false);
  const [hasCookieAccess, setHasCookieAccess] = useState(false);

  const handleShowElementsResponse = (resp) => {
    console.log("handleShowElementsResponse: ", resp);
    if (resp.loginButton) {
      if (resp.loginButton.hide) setHide({ ...hide, loginButton: true });
      else setHide({ ...hide, loginButton: false });
    }
    if (resp.spinner) {
      console.log("resp.spinner: ", resp.spinner);
      if (resp.spinner.hide) setHide({ ...hide, spinner: true });
      else setHide({ ...hide, spinner: false });
    }
    if (resp.warning) {
      if (resp.warning.hide) setHide({ ...hide, warning: true });
      else {
        setHide({ ...hide, warning: false, spinner: false });
        setMessage({
          ...message,
          warning: resp.warning.message || "Connecting",
        });
      }
    }
    if (resp.error) {
      if (resp.error.hide) setHide({ ...hide, error: true });
      else {
        setHide({ ...hide, error: false });
        setMessage({ ...message, error: resp.error.message || ""});
      }
    }
  };

  const onGetAccountsSuccess = (accounts) => {
    setFetchedAccounts(true);
    setAccounts(accounts);
    setHide({ error: true, spinner: true, loginButton: true, warning: true });
  };

  const onGetAccountsFailure = (errorString) => {
    setHide({
      error: false,
      loginButton: false,
      spinner: true,
      warning: true,
    });
    setMessage({
      error: "",
      warning: "",
    });
  };

  /**
   * By end of 2024, Google is stopping cookies access
   * and would need explicit permission from users for using it.
   * The below function will be used for that
   */
  const handleCookieAccessInit = async () => {
    if (!document.hasStorageAccess) {
      // Storage Access API is not supported so best we can do is
      // hope it's an older browser that doesn't block 3P cookies.
      // hasCookieAccess = true;
      setHasCookieAccess(true);
    } else {
      // Check whether access has been granted using the Storage Access API.
      // Note on page load this will always be false initially so we could be
      // skipped in this example, but including for completeness for when this
      // is not so obvious.
      let hasAccess = await document.hasStorageAccess();
      if (!hasAccess) {
        try {
          await document.requestStorageAccess();
          setHasCookieAccess(true);
          console.log("cookie access granted");
        } catch (err) {
          // Access was not granted and it may be gated behind an interaction
          setHasCookieAccess(false);
          console.log("cookie access denied");
          return;
        }
      } else {
        console.log("cookie access previously granted");
        setHasCookieAccess(true);
      }
    }
  };

  const initialiseServer = () => {
    console.log("initialiseServer");
    toBackground("onelogin.getServerInfo", {}, (res) => {
      console.log("onelogin.getServerInfo (background): ", res);
      if (res && res.status === "SUCCESS") {
        setServerUrl(res?.data?.serverUrl || "");
        // Initlise all the server url's from here
        getAccounts(onGetAccountsSuccess, onGetAccountsFailure);
      } else {
        // handle error case here
        setHide({
          error: false,
          loginButton: false,
          spinner: true,
          warning: true,
        });
        setMessage({
          error: res.data,
          warning: "",
        });
      }
    });
  };

  const initialise = () => {
    console.log("initialising");
    setHide({ hideError: true, hideWarning: true, hideSpinner: false });
    const resp = showElements("connecting");
    handleShowElementsResponse(resp);

    /**
     * Initialise server
     */
    initialiseServer();
  };

  useEffect(() => {
    initialise();
  }, []);

  return (
    <div className={"popup-body"}>
      <Header
        hide={hide}
        message={message}
        filterValue={filterValue}
        setFilterValue={setFilterValue}
        serverUrl={serverUrl}
      />

      {/*
                To remove cookie issue:
                Asks for user's permission
                Take decission on this later
            */}
      {/* <button onClick={handleCookieAccessInit}>
                Grant cookie access
            </button> */}
      {fetchedAccounts && accounts.length ? (
        <AllApps accounts={accounts} filterValue={filterValue} />
      ) : undefined}

      {/*
                Hide the serverurl in production
            */}
      {portalPageClassifier.isProduction(serverUrl) ? null : (
        <div id="popup-footer"className="popup-footer">
          <div id="server_info">&nbsp; {serverUrl}</div>
        </div>
      )}
    </div>
  );
};

export default App;
