/**
 * Sends message to the background script
 */
export function toBackground(messageName, messageData, callback) {
  if (typeof messageData === "function") {
    callback = messageData;
    messageData = undefined;
  }

  if (typeof callback !== "function") {
    callback = function () {};
  }

  chrome.runtime.sendMessage({ type: messageName, params: messageData || {} }, callback);
}
