/*
 Classify given url in order to provide functionality specific to portal, non-portal.
 Is mainly used in content scripts to launch certain tasks based on where user navigated.
 */

import * as urlMod from "url";

const ALL_PORTAL_CLASIFICATIONS = [
  "portalLoginUrl",
  "legacyPortalSiteListUrl",
  "portalSiteListUrl",
  "portalSettingsUrl",
];

const PORTAL_SITE_CLASIFICATIONS = ["portalSiteListUrl", "legacyPortalSiteListUrl"];

var portalPageClassifier = {
  portalUrlPatterns: {
    formServiceStartLoginUrl: /\/form-service\/(internal\/testApps\/)?start\//i,
    formServiceLoginApiUrl: /\/form-service\/(internal\/testApps\/)?login\//i,
    portalStartLoginUrl: /\/(start|launch|client\/apps\/select)\/.*/i,
    portalLoginUrl: /^\/login2?\/?$/i,
    portalLogoutUrl: /^\/logout\/?$/i,
    legacyPortalSiteListUrl: /\/client\/apps\/?$/i,
    portalSiteListUrl: /\/portal\/?$/i, // @TODO: for new portal, it currently matches also /portal#something - this may not be portalSiteUrl on new portal
    portalSettingsUrl: /\/(client\/settings|profile)($|\/.*)/i,
    portalSessionUrl: /\/sessions\/?$/i,
  },

  matchPatterns: function (patterns, url) {
    let origin = null;
    try {
      origin = new URL(url).origin;
    } catch (e) {
      // report or log to console or nothing todo?
      return false;
    }
    for (var i = 0; i < patterns.length; i++) {
      if (patterns[i].test(origin)) {
        return true;
      }
    }
    return false;
  },

  isOneloginPortal: function (url) {
    if (!url) return false;

    var patterns = [
      /^https:\/\/(?!(www|api)\.)[a-z0-9.-]+\.onelogin\.com(:|#|\/|$|\?)/,
      /^https?:\/\/(?!(www|api)\.)[a-z0-9.-]+\.onelogin\.local(:|#|\/|$|\?)/,
      /^https:\/\/(?!(www|api)\.)[a-z0-9.-]+\.onelogin-shadow\d\d\.com(:|#|\/|$|\?)/,
    ];

    return portalPageClassifier.matchPatterns(patterns, url.toLowerCase());
  },

  classifyPortalUrl: function (url) {
    var parsedUrl = url ? urlMod.parse(url) : undefined,
      key;

    if (!url || !parsedUrl) {
      return undefined;
    }

    if (!portalPageClassifier.isOneloginPortal(url)) {
      return "notPortalUrl";
    }

    for (key in portalPageClassifier.portalUrlPatterns) {
      if (portalPageClassifier.portalUrlPatterns[key].test(parsedUrl.pathname)) {
        return key;
      }
    }

    return "otherPortalUrl";
  },

  isProduction: function (url) {
    return /https?:\/\/.+\.onelogin\.com(:|\/|$)/.test(url);
  },

  filterAllPortalTabs: function (tabs) {
    return portalPageClassifier._filterTabsByClasification(tabs, ALL_PORTAL_CLASIFICATIONS);
  },

  filterPortalSiteTabs: function (tabs) {
    return portalPageClassifier._filterTabsByClasification(tabs, PORTAL_SITE_CLASIFICATIONS);
  },

  _filterTabsByClasification: function (tabs, validUrlTypes) {
    return tabs.filter(function (tab) {
      const tabType = portalPageClassifier.classifyPortalUrl(tab.url);
      return validUrlTypes.indexOf(tabType) !== -1;
    });
  },
};

export default portalPageClassifier;
