import { COLORS } from "../../const.js";
import { toBackground } from "../../messages/index.js";
import "../css/main.css";
import urlOpener from "../../global/onelogin/urlOpener.js";
import { useEffect, useRef } from "react";

export default function Header({ hide, message, filterValue, setFilterValue, serverUrl }) {
  const searchRef = useRef(null);

  useEffect(() => {
    if (hide.loginButton == true && hide.spinner == true && hide.error == true) {
      if (searchRef && searchRef.current) {
        searchRef.current?.focus();
      }
    }
  }, [hide]);

  const openPortal = (event) => {
    event.preventDefault();
    toBackground("onelogin.openPortal", {}, function (response) {
      if (response.status === "SUCCESS") {
        if (response.data.portalTabSelected) {
          urlOpener.closePopupWindow();
        } else if (response.data.noPortalTab) {
          urlOpener.openUrlInNewOrEmptyTab(response.data.serverUrl);
        }
      }
    });
  };

  return (
    <div id="popup-header">
      <div className={"popup-title"}>
        <a
          id="server-link"
          href={`${serverUrl || "https://www.onelogin.com/"}`}
          target="_blank"
          className="extension-logo"
        ></a>
      </div>
      {!hide.error ? (
        <div id="warning"className="popup-message">
          <p style={{ color: "red"}}>{message.error || ""}</p>
        </div>
      ) : undefined}

      {!hide.warning ? (
        <div id="warning"className="popup-message">
          <p>{message.warning || "Connecting"}</p>
        </div>
      ) : undefined}

      {!hide.spinner ? (
        <div id="spinner-wrapper"className="spinner-wrapper">
          <div id="spinner"className="spinner"title="spinner"></div>
        </div>
      ) : undefined}

      {hide.loginButton == false ? (
        <div className="login-button-wrapper">
          <div className="content-block">
            <button
              className="login-button"
              style={{
                color: COLORS.WHITE,
                backgroundColor: COLORS.ACTION_COLORS.BLUE_MAIN,
              }}
              // look="primary"
              onClick={openPortal}
            >
              LOG IN
            </button>
          </div>
        </div>
      ) : undefined}

      {hide.loginButton == true && hide.spinner == true && hide.error == true ? (
        <div className="filter-wrapper"id="filter-wrapper">
          <input
            ref={searchRef}
            placeholder="Search"
            id="filter-input"
            name="filter-input"
            // autofocus
            className="filter-input"
            spellcheck="false"
            value={filterValue}
            onChange={(e) => {
              setFilterValue(e.target.value);
            }}
          />
        </div>
      ) : undefined}
    </div>
  );
}
