var commonEmptyUrlsPatterns = [/^about:blank$/i];

var emptyUrlsPatterns = {
  chrome: [/^chrome:\/\/newtab\/$/i],
  firefox: [/^about:newtab$/i, /^about:home$/i],
  safari: [],
  ie: [/^edge:newsfeed$/i],
  edge: [/^edge:\/\/newtab\/$/i],
  edge_legacy: [
    /https:\/\/www.msn.com\/spartan\/(ntp|dhp).*/i,
    /ms-browser-extension:\/\/OneLoginDevforEdge_.*\/firstRun\/firstRun.html$/i,
    /ms-browser-extension:\/\/EdgeExtension_OneLoginOneLoginforEdge_.*\/firstRun\/firstRun.html$/i,
  ],
};

function _openUrlInNewOrCurrentTab(url, useCurrent) {
  _getActiveTab(function (activeTab) {
    var params = { url: url };
    if (!activeTab || !useCurrent(activeTab.url)) {
      if (!!activeTab) {
        params.index = activeTab.index + 1;
      }
      chrome.tabs.create({ url: url });
    } else {
      chrome.tabs.update(activeTab.id, { url: url });
    }
    closePopupWindow();
  });
}

function _getActiveTab(callback) {
  chrome.tabs.query({ active: true, currentWindow: true }, function (tabs) {
    callback(Array.isArray(tabs) ? tabs[0] : null);
  });
}

/**
 * Checks whether the given url is interpreted as 'empty page' on the given platform.
 *
 * @param {String} url url to check
 * @return {boolean} true if the given url is url of empty page, false otherwise
 */
function isEmptyPageUrl(url) {
  var platformName = "chrome"; // @todo: get platform name dynamically
  var patternsToCheck = commonEmptyUrlsPatterns.concat(emptyUrlsPatterns[platformName]);
  return patternsToCheck.some((pattern) => pattern.test(url));
}

/**
 * Opens the give url in a new tab.
 *
 * @param {String} url url to open
 */
function openUrlInCurrentTab(url) {
  _openUrlInNewOrCurrentTab(url, function () {
    return true;
  });
}

/**
 * Opens a new tab or sets the url to the active.
 * When the active tab is 'empty' page the url is set to it otherwise a new tab with the given url is opened.
 *
 * @param {String} url
 */
function openUrlInNewOrEmptyTab(url) {
  _openUrlInNewOrCurrentTab(url, function (tabUrl) {
    return isEmptyPageUrl(tabUrl);
  });
}

/**
 * Gets the url of the active tab. Provided as a callback with the url as parameter.
 *
 * @param callback
 */
function getActiveTabUrl(callback) {
  _getActiveTab(function (activeTab) {
    callback(!!activeTab ? activeTab.url : null);
  });
}

/**
 * Closes the popup window
 */
function closePopupWindow() {
  window.close();
}

export default {
  openUrlInNewOrEmptyTab,
  isEmptyPageUrl,
  getActiveTabUrl,
  openUrlInCurrentTab,
  closePopupWindow,
};
