import { toBackground } from "../messages/index.js";
import urlOpener from "./onelogin/urlOpener.js";

export function showElements(connectionStatus, accounts) {
  var popupTooltip;
  var resp;
  switch (connectionStatus) {
    case "connecting":
      popupTooltip = "OneLogin\nStatus: Connecting.";
      resp = {
        warning: {
          hide: false,
          message: "Connecting",
        },
        spinner: {
          hide: false,
        },
        loginButton: {
          hide: true,
        },
      };
      break;
    case "failed":
      popupTooltip = "OneLogin\nStatus: Not available.";

      resp = {
        warning: {
          hide: true,
        },
        spinner: {
          hide: true,
        },
        loginButton: {
          hide: true,
        },
        error: {
          hide: false,
          message: "We are sorry, OneLogin is not available at the moment.",
        },
      };
      break;
    case "loggedOut":
      // setLinkUrl(document.getElementById('login-link'), serverInfo.serverUrl);
      popupTooltip = "OneLogin\nStatus: Not logged in.";
      resp = {
        warning: {
          hide: false,
          message: "Please log in to access your apps.",
        },
        spinner: {
          hide: true,
        },
        loginButton: {
          hide: false,
        },
      };
      break;
    case "connected":
      popupTooltip = "OneLogin\nStatus: Logged in.";

      resp = {
        warning: {
          hide: accounts && accounts.length,
          message:
            "You don't have any apps set up.<br>You can configure your cloud apps or request access to team apps from <a id='login-link' class='login-link'>OneLogin</a>.",
        },
        spinner: {
          hide: true,
        },
        loginButton: {
          hide: true,
        },
      };
      break;
  }
  if (!!chrome.action.setTitle) {
    chrome.action.setTitle({
      title: popupTooltip,
    });
  }

  return resp;
}

export function getAccounts(onSuccess, onFailure) {
  console.log("Get accounts");
  urlOpener.getActiveTabUrl(function (activeTabUrl) {
    var params = !!activeTabUrl ? { tabUrl: activeTabUrl } : {};
    toBackground("onelogin.getAccounts", params, function (response) {
      if (response.status == "ERROR") {
        onFailure(response.data.message || "");
      } else {
        onSuccess(response?.data || []);
      }
    });
  });
}
