import { useEffect, useRef, useState } from "react";
import urlOpener from "../../global/onelogin/urlOpener.js";
import "../css/apps.css";

function appSortCompare(app1, app2) {
  const app1Name = (app1?.name || "").toLowerCase();
  const app2NAme = (app2?.name || "").toLowerCase();

  if (app1Name < app2NAme) return -1;
  return 1;
}

function SingleApp({ account, fromLoginPage, selected }) {
  const [iconUrl, setIconUrl] = useState("");

  useEffect(() => {
    var iconUrl = account.icons && account.icons.square_24x24;
    setIconUrl(iconUrl);
  }, [account]);

  function isUsername(username) {
    return !!username;
  }

  const onAppClick = () => {
    var startUrl = account.startUrl + "?client="+ "chrome"+ "Ext";

    if (fromLoginPage) {
      urlOpener.openUrlInCurrentTab(startUrl);
    } else {
      urlOpener.openUrlInNewOrEmptyTab(startUrl);
    }
  };

  return (
    <div
      className="list-item account-item visible"
      style={{
        backgroundColor: selected ? "#f3f3f4": undefined,
        cursor: "pointer",
      }}
      tabIndex={0}
      onClick={onAppClick}
    >
      <div className="content">
        <img src={iconUrl} className="icon"/>
        <div className="creds">
          <p className={`title ${!isUsername(account.username) ? "only": ""}`}>{account.name}</p>
          <p className={`description ${!isUsername(account.username) ? "hidden": ""}`}>
            {account.username}
          </p>
        </div>
      </div>
    </div>
  );
}

export default function AllApps({ accounts, filterValue }) {
  /**
   *
   */
  const [loginUrlApps, setLoginUrlApps] = useState([]);
  const [privateApps, setPrivateApps] = useState([]);
  const [teamApps, setTeamApps] = useState([]);
  const [allApps, setAllApps] = useState([]);

  const [selectedIndex, setSelectedIndex] = useState(0);

  const listRef = useRef(null); // Reference to the list container

  const totalLengthOfItems = allApps.length;

  useEffect(() => {
    var lApps = [];
    var pApps = [];
    var tApps = [];
    accounts.map(function (account) {
      //so far supported only in chrome
      if (!!account.isLoginUrlMatch) {
        lApps.push(account);
      }
      if (!!account.isPrivate) {
        pApps.push(account);
      } else {
        tApps.push(account);
      }
    });
    lApps.sort(appSortCompare);
    pApps.sort(appSortCompare);
    tApps.sort(appSortCompare);

    /**
     * Filter the apps based on filter string
     */
    if (filterValue) {
      lApps = lApps.filter(
        (app) =>
          (app.name && app.name.toLowerCase().includes(filterValue.toLowerCase())) ||
          (app.username && app.username.toLowerCase().includes(filterValue.toLowerCase()))
      );

      pApps = pApps.filter(
        (app) =>
          (app.name && app.name.toLowerCase().includes(filterValue.toLowerCase())) ||
          (app.username && app.username.toLowerCase().includes(filterValue.toLowerCase()))
      );

      tApps = tApps.filter(
        (app) =>
          (app.name && app.name.toLowerCase().includes(filterValue.toLowerCase())) ||
          (app.username && app.username.toLowerCase().includes(filterValue.toLowerCase()))
      );
    }
    setLoginUrlApps(lApps);
    setPrivateApps(pApps);
    setTeamApps(tApps);
    setAllApps([...lApps, ...pApps, ...tApps]);
    setSelectedIndex(-1);
  }, [accounts, filterValue]);

  /**
   * index ranges from 0 to (totalLengthOfItems-1)
   */
  const getCurrentAppHeaderInViewAndTheOffset = (index) => {
    if (index < loginUrlApps.length) {
      return {
        memberOf: "LOGIN",
        offset: index,
      };
    }
    // not part of login now
    if (index >= loginUrlApps.length && index < loginUrlApps.length + privateApps.length) {
      let offset = index - loginUrlApps.length;
      return {
        memberOf: "PRIVATE",
        offset: offset,
      };
    }
    let offset = loginUrlApps.length
      ? privateApps.length
        ? index - loginUrlApps.length - privateApps.length - 1
        : index - loginUrlApps.length
      : privateApps.length
        ? index - privateApps.length
        : index;
    return {
      memberOf: "COMPANY",
      offset: offset,
    };
    /**
     * Check offset logic here
     */
  };

  // const handleKeyDown = (event) => {
  //   if (event.key === "ArrowDown") {
  //     setSelectedIndex((prevIndex) => (prevIndex < totalLengthOfItems - 1 ? prevIndex + 1 : 0));
  //   } else if (event.key === "ArrowUp") {
  //     setSelectedIndex((prevIndex) => (prevIndex > 0 ? prevIndex - 1 : totalLengthOfItems - 1));
  //   } else if (event.key === "Enter") {
  //     // Do something on selected item
  //     const listItem = listRef.current.children[selectedIndex];
  //     if (listItem && listItem.click) {
  //       listItem.click();
  //     }
  //   }
  // };
  const getListItemFromIndex = (index) => {
    const { memberOf, offset } = getCurrentAppHeaderInViewAndTheOffset(index);
    /**
     * Get the list item and click
     */
    let listItem;
    if (!listRef || !listRef.current || !listRef.current.children) return listItem;

    if (memberOf == "LOGIN") {
      listItem = listRef.current.children[0]?.children[1 + offset] || undefined;
    } else if (memberOf == "PRIVATE") {
      let childIndex = loginUrlApps.length ? 1 : 0;
      listItem = listRef.current.children[childIndex]?.children[1 + offset] || undefined;
    } else {
      let childIndex = loginUrlApps.length
        ? privateApps.length
          ? 2
          : 1
        : privateApps.length
          ? 1
          : 0;
      listItem = listRef.current.children[childIndex]?.children[1 + offset] || undefined;
    }
    return listItem;
  };

  const handleKeyDown = (event) => {
    if (event.key === "ArrowDown") {
      setSelectedIndex((prevIndex) => (prevIndex < totalLengthOfItems - 1 ? prevIndex + 1 : 0));
    } else if (event.key === "ArrowUp") {
      setSelectedIndex((prevIndex) => (prevIndex > 0 ? prevIndex - 1 : totalLengthOfItems - 1));
    } else if (event.key === "Enter") {
      // Do something on selected item
      // const listItem = listRef.current.children[selectedIndex];
      // if (listItem && listItem.click) {
      //   listItem.click();
      // }

      /**
       * Get the list item and click
       */
      let listItem = getListItemFromIndex(selectedIndex);
      if (listItem && listItem.click) {
        listItem.click();
      }
    }
  };

  // Attach the keydown event listener
  useEffect(() => {
    window.addEventListener("keydown", handleKeyDown);

    // Clean up the event listener on unmount
    return () => {
      window.removeEventListener("keydown", handleKeyDown);
    };
  }, [selectedIndex]);

  useEffect(() => {
    const listItem = getListItemFromIndex(selectedIndex);
    if (listItem) {
      listItem.scrollIntoView({ behavior: "smooth", block: "nearest"});
    }
  }, [selectedIndex]);

  return (
    <div
      style={{
        overflowX: "hidden",
        overflowY: "auto",
        height: "300px",
        maxHeight: "300px",
      }}
    >
      <div className=""style={{ backgroundColor: "inherit"}} ref={listRef}>
        {/* {allApps.length
          ? allApps.map((app, idx) => (
              <SingleApp
                account={app}
                fromLoginPage={true}
                key={`${idx}_${app.id}`}
                selected={idx === selectedIndex}
              />
            ))
          : undefined} */}
        {loginUrlApps.length ? (
          <div className="list-item section-title">
            <div className="text">Login to current app</div>
            {loginUrlApps.map((app, idx) => (
              <SingleApp
                account={app}
                fromLoginPage={true}
                key={`${idx}_${app.id}`}
                selected={
                  getCurrentAppHeaderInViewAndTheOffset(selectedIndex).memberOf == "LOGIN"&&
                  getCurrentAppHeaderInViewAndTheOffset(selectedIndex).offset == idx
                }
              />
            ))}
          </div>
        ) : undefined}
        {privateApps.length ? (
          <div className="list-item section-title">
            <div className="text">Private apps</div>
            {privateApps.map((app, idx) => (
              <SingleApp
                account={app}
                fromLoginPage={false}
                key={`${idx}_${app.id}`}
                selected={
                  getCurrentAppHeaderInViewAndTheOffset(selectedIndex).memberOf == "PRIVATE"&&
                  getCurrentAppHeaderInViewAndTheOffset(selectedIndex).offset == idx
                }
              />
            ))}
          </div>
        ) : undefined}
        {teamApps.length ? (
          <div className="list-item section-title">
            <div className="text">Company apps</div>
            {teamApps.map((app, idx) => (
              <SingleApp
                account={app}
                fromLoginPage={false}
                key={`${idx}_${app.id}`}
                selected={
                  getCurrentAppHeaderInViewAndTheOffset(selectedIndex).memberOf == "COMPANY"&&
                  getCurrentAppHeaderInViewAndTheOffset(selectedIndex).offset == idx
                }
              />
            ))}
          </div>
        ) : undefined}
      </div>
    </div>
  );
}
